import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.apache.commons.text.StringEscapeUtils;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize and escape user input to prevent XSS attacks
        String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);

        String htmlResponse = "<html><body>Hello, " + safeUserInput + "</body></html>";

        response.setContentType("text/html");
        response.setCharacterEncoding("UTF-8");

        PrintWriter out = response.getWriter();
        out.write(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
